// Unit 26 — Habría sido...
// Condicional Compuesto & Past Counterfactuals

export default {n:26,lang:"es",srcLang:"en",track:"v2",title:"Habría sido...",sub:"Condicional Compuesto & Past Counterfactuals",icon:"⏳",level:"B2.1",color:"#7B5EE8",lessons:[
  {id:"esp26l1",title:"Habría hablado",icon:"🔧",xp:20,board:true,steps:[
        {type:"intro",title:"Habría hablado",desc:"Learn to form the condicional compuesto: what would have happened. This tense combines the conditional of haber with a past participle.",goals:["Form the condicional compuesto with regular verbs","Conjugate haber in the conditional","Use past participles with -ado and -ido endings"]},
        {type:"teach",trg:"habría hablado",src:"I would have spoken",pos:"intj",gender:null,phonetic:"ah-BREE-ah ah-BLA-do",note:"Conditional of haber + past participle.\nhabría + hablado = would have spoken.",example:"A: ¿Por qué no le dijiste la verdad?\nB: Habría hablado, pero no tuve oportunidad.\nA: Siempre hay oportunidad.\nB: Tienes razón. Habría hablado si hubiera tenido más tiempo.\nA: La próxima vez, no lo dudes.",exampleSrc:"A: Why didn't you tell him the truth?\nB: I would have spoken, but I didn't have the chance.\nA: There is always a chance.\nB: You're right. I would have spoken if I had had more time.\nA: Next time, don't hesitate.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"habrías comido",src:"you would have eaten",pos:"intj",gender:null,phonetic:"ah-BREE-as ko-MEE-do",note:"Habrías = you (informal) would have.\nComido = past participle of comer.",example:"A: No comiste nada en la fiesta.\nB: Habrías comido tampoco si hubieras visto la comida.\nA: ¿Tan mala estaba?\nB: Terrible. Habrías comido mejor en casa.\nA: Menos mal que no fui.",exampleSrc:"A: You didn't eat anything at the party.\nB: You wouldn't have eaten either if you had seen the food.\nA: Was it that bad?\nB: Terrible. You would have eaten better at home.\nA: Good thing I didn't go.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"habría vivido",src:"he/she would have lived",pos:"intj",gender:null,phonetic:"ah-BREE-ah vee-VEE-do",note:"Third person uses habría, same as first person.\nContext determines who: yo/él/ella/usted.",example:"A: Mi abuelo habría vivido más años con mejor medicina.\nB: Es verdad. La medicina ha avanzado mucho.\nA: Habría vivido para conocer a sus bisnietos.\nB: Eso habría sido maravilloso.\nA: Sin duda. Lo echo mucho de menos.",exampleSrc:"A: My grandfather would have lived more years with better medicine.\nB: That's true. Medicine has advanced a lot.\nA: He would have lived to meet his great-grandchildren.\nB: That would have been wonderful.\nA: Without a doubt. I miss him a lot.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"verb_table",title:"Condicional compuesto: haber",note:"Only haber conjugates. The participle never changes.\n-ar verbs: -ado (hablado)\n-er/-ir verbs: -ido (comido, vivido)",groups:[
          {
            header:"Singular",
            rows:[{"0":"yo","1":"habría + -ado/-ido"},{"0":"tú","1":"habrías + -ado/-ido"},{"0":"él/ella/usted","1":"habría + -ado/-ido"}]
          },
          {
            header:"Plural",
            rows:[{"0":"nosotros","1":"habríamos + -ado/-ido"},{"0":"vosotros","1":"habríais + -ado/-ido"},{"0":"ellos/ustedes","1":"habrían + -ado/-ido"}]
          }
        ],label:"haber (conditional) + participio pasado"},
        {type:"teach",trg:"habríamos viajado",src:"we would have traveled",pos:"intj",gender:null,phonetic:"ah-BREE-ah-mos vya-HA-do",note:"Habríamos = we would have.\nViajado = past participle of viajar (to travel).",example:"A: ¿Fuisteis de vacaciones?\nB: No. Habríamos viajado a Italia, pero no teníamos dinero.\nA: Qué pena. Italia es preciosa.\nB: Habríamos viajado en tren por toda Europa.\nA: Quizás el año que viene podáis ir.",exampleSrc:"A: Did you go on vacation?\nB: No. We would have traveled to Italy, but we didn't have money.\nA: What a shame. Italy is beautiful.\nB: We would have traveled by train all over Europe.\nA: Maybe next year you can go.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"habrían llegado",src:"they would have arrived",pos:"intj",gender:null,phonetic:"ah-BREE-an ye-GA-do",note:"Habrían = they/you all would have.\nLlegado = past participle of llegar (to arrive).",example:"A: Los invitados no vinieron a la cena.\nB: Habrían llegado a tiempo si no hubiera habido tráfico.\nA: ¿Tanto tráfico había?\nB: Un accidente en la autopista. Habrían llegado antes de las ocho.\nA: Qué mala suerte.",exampleSrc:"A: The guests didn't come to dinner.\nB: They would have arrived on time if there hadn't been traffic.\nA: Was there that much traffic?\nB: An accident on the highway. They would have arrived before eight.\nA: What bad luck.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"How to form the condicional compuesto",text:"Two parts, always:\n1. Conditional of haber: habría, habrías, habría, habríamos, habríais, habrían\n2. Past participle: -ar = -ado, -er/-ir = -ido\n\nThe participle NEVER changes for gender or number.\nHabría comido works for yo, él, ella, and usted.",icon:"💡"},
        {type:"mc",q:"'Habríamos comprado' means:",opts:["We would have bought","They would have bought","You would have bought","I would have bought"],ans:"We would have bought",hint:"The -amos ending on habríamos signals the nosotros form."},
        {type:"mc",q:"Which is correct for 'she would have studied'?",opts:["Habría estudiado","Habrías estudiado","Habríamos estudiado","Habrían estudiada"],ans:"Habría estudiado",hint:"Third person singular uses the same form as first person. The participle does not change."},
        {type:"fb",opts:["habrían","habría","habrías","habríamos"],hint:"The third person plural conditional of haber ends in -ían.",s:"Ellos {1} salido antes.",a:"habrían"},
        {type:"fb",opts:["escrito","escribido","escribo","escribió"],hint:"Escribir has an irregular past participle.",s:"Yo habría {1} la carta.",a:"escrito"},
        {type:"mc",q:"In 'habría bailado', what type of word is 'bailado'?",opts:["A conjugated verb","A past participle","An infinitive","A gerund"],ans:"A past participle",hint:"The -ado ending on an -ar verb stem signals this form."},
        {type:"match",pairs:[
          {trg:"habría hablado",src:"I/he/she would have spoken"},
          {trg:"habrías comido",src:"you would have eaten"},
          {trg:"habríamos vivido",src:"we would have lived"},
          {trg:"habrían salido",src:"they would have left"},
          {trg:"habríais dicho",src:"you all would have said"}
        ]},
        {type:"fb",opts:["habríamos","habrían","habría","habrías"],hint:"The nosotros conditional of haber includes -íamos.",s:"Nosotros {1} ido al cine.",a:"habríamos"},
        {type:"mc",q:"The past participle of 'vender' (to sell) is:",opts:["vendado","vendido","vendiendo","vender"],ans:"vendido",hint:"Regular -er verbs form the participle with -ido."},
        {type:"mc",q:"'Tú habrías cantado' is best translated as:",opts:["You would have sung","You had sung","You will have sung","You are singing"],ans:"You would have sung",hint:"The conditional of haber plus a participle expresses a hypothetical past action."},
        {type:"fb",opts:["habría","habrían","habrías","habríamos"],hint:"María is third person singular, the same form as yo.",s:"María {1} preparado la cena.",a:"habría"}
  ]},
  {id:"esp26l2",title:"Hubiera hablado",icon:"🌀",xp:20,board:true,steps:[
        {type:"intro",title:"Hubiera hablado",desc:"The pluscuamperfecto de subjuntivo expresses hypothetical past situations. It is the subjunctive partner of the condicional compuesto.",goals:["Form the pluscuamperfecto de subjuntivo","Use hubiera/hubiese + past participle","Understand when this tense appears"]},
        {type:"teach",trg:"hubiera hablado",src:"I had spoken (subjunctive)",pos:"intj",gender:null,phonetic:"oo-BYEH-ra ah-BLA-do",note:"Hubiera + past participle = had done (hypothetical).\nUsed in the si clause of past counterfactuals.",example:"A: ¿Por qué no dijiste nada?\nB: Si hubiera hablado, nadie me habría escuchado.\nA: Eso no es cierto.\nB: Tal vez. Pero no hubiera hablado de todos modos.\nA: A veces hay que ser valiente.",exampleSrc:"A: Why didn't you say anything?\nB: If I had spoken, nobody would have listened.\nA: That's not true.\nB: Maybe. But I wouldn't have spoken anyway.\nA: Sometimes you have to be brave.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"hubieras comido",src:"you had eaten (subjunctive)",pos:"intj",gender:null,phonetic:"oo-BYEH-ras ko-MEE-do",note:"Hubieras = you (informal) had (subjunctive).\nAppears after si in unreal past conditions.",example:"A: Estabas muy cansado ayer.\nB: Si hubieras comido bien, habrías tenido más energía.\nA: Lo sé. No desayuné.\nB: Si hubieras comido algo, todo habría ido mejor.\nA: Mañana no me lo salto.",exampleSrc:"A: You were very tired yesterday.\nB: If you had eaten well, you would have had more energy.\nA: I know. I didn't have breakfast.\nB: If you had eaten something, everything would have gone better.\nA: Tomorrow I won't skip it.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"hubiera vivido",src:"he/she had lived (subjunctive)",pos:"intj",gender:null,phonetic:"oo-BYEH-ra vee-VEE-do",note:"Third person hubiera = same as first person.\nContext determines who the subject is.",example:"A: Mi tía se mudó a Argentina.\nB: Si hubiera vivido en España, habríamos sido más cercanos.\nA: ¿La echas de menos?\nB: Mucho. Si hubiera vivido aquí, todo sería diferente.\nA: Al menos podéis hablar por video.",exampleSrc:"A: My aunt moved to Argentina.\nB: If she had lived in Spain, we would have been closer.\nA: Do you miss her?\nB: A lot. If she had lived here, everything would be different.\nA: At least you can video call.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"verb_table",title:"Pluscuamperfecto de subjuntivo: haber",note:"Two forms exist: hubiera and hubiese. Both are correct.\nHubiera is more common in speech.\nThe participle follows the same rules: -ado, -ido.",groups:[
          {
            header:"Singular",
            rows:[{"0":"yo","1":"hubiera (hubiese)"},{"0":"tú","1":"hubieras (hubieses)"},{"0":"él/ella/usted","1":"hubiera (hubiese)"}]
          },
          {
            header:"Plural",
            rows:[{"0":"nosotros","1":"hubiéramos (hubiésemos)"},{"0":"vosotros","1":"hubierais (hubieseis)"},{"0":"ellos/ustedes","1":"hubieran (hubiesen)"}]
          }
        ],label:"hubiera/hubiese + participio pasado"},
        {type:"teach",trg:"hubiéramos sabido",src:"we had known (subjunctive)",pos:"intj",gender:null,phonetic:"oo-BYEH-ra-mos sa-BEE-do",note:"Hubiéramos = we had (subjunctive).\nSabido = past participle of saber (to know).",example:"A: No sabíamos que la tienda cerraba temprano.\nB: Si hubiéramos sabido, habríamos ido antes.\nA: Nadie nos avisó.\nB: Si hubiéramos sabido la hora, no habríamos perdido el viaje.\nA: La próxima vez preguntamos.",exampleSrc:"A: We didn't know the store closed early.\nB: If we had known, we would have gone earlier.\nA: Nobody told us.\nB: If we had known the time, we wouldn't have wasted the trip.\nA: Next time we'll ask.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"hubieran venido",src:"they had come (subjunctive)",pos:"intj",gender:null,phonetic:"oo-BYEH-ran ve-NEE-do",note:"Hubieran = they had (subjunctive).\nVenido = past participle of venir (irregular: not venío).",example:"A: Tus primos no vinieron a la boda.\nB: Si hubieran venido, la fiesta habría sido mejor.\nA: ¿Por qué no vinieron?\nB: Estaban de viaje. Si hubieran venido, habrían traído regalos.\nA: Qué pena que no pudieron estar.",exampleSrc:"A: Your cousins didn't come to the wedding.\nB: If they had come, the party would have been better.\nA: Why didn't they come?\nB: They were traveling. If they had come, they would have brought gifts.\nA: Too bad they couldn't be there.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Hubiera vs hubiese",text:"Both forms are grammatically identical:\nSi hubiera sabido = Si hubiese sabido\n\nHubiera is more common in everyday speech.\nHubiese appears more in formal writing.\nUse whichever feels natural. Most learners stick with hubiera.",icon:"💡"},
        {type:"mc",q:"'Si hubieras estudiado' means:",opts:["If you had studied","If you studied","If you will study","If you study"],ans:"If you had studied",hint:"Hubieras + participle refers to a past situation that did not happen."},
        {type:"mc",q:"Which form is the nosotros pluscuamperfecto de subjuntivo of 'saber'?",opts:["Hubiéramos sabido","Habríamos sabido","Hubieran sabido","Habían sabido"],ans:"Hubiéramos sabido",hint:"The subjunctive past perfect uses hubiera forms, not habría."},
        {type:"fb",opts:["hubiera","habría","hubieras","habrían"],hint:"The si clause uses the subjunctive form of haber.",s:"Si ella {1} llegado a tiempo, todo habría salido bien.",a:"hubiera"},
        {type:"mc",q:"'Hubieran' corresponds to which subject?",opts:["yo","tú","nosotros","ellos/ustedes"],ans:"ellos/ustedes",hint:"The -an ending matches third person plural."},
        {type:"fb",opts:["hubiéramos","habríamos","hubieran","habrían"],hint:"Nosotros + subjunctive past perfect needs the -éramos form.",s:"Si nosotros {1} tenido dinero, habríamos comprado la casa.",a:"hubiéramos"},
        {type:"match",pairs:[
          {trg:"hubiera hablado",src:"I/he/she had spoken (subj.)"},
          {trg:"hubieras comido",src:"you had eaten (subj.)"},
          {trg:"hubiéramos vivido",src:"we had lived (subj.)"},
          {trg:"hubieran salido",src:"they had left (subj.)"},
          {trg:"hubierais dicho",src:"you all had said (subj.)"}
        ]},
        {type:"mc",q:"In 'Si hubiera llovido, no habríamos salido', which part is subjunctive?",opts:["no habríamos salido","Si hubiera llovido","Both parts","Neither part"],ans:"Si hubiera llovido",hint:"The si clause always holds the subjunctive form."},
        {type:"fb",opts:["hubieras","hubiera","hubiéramos","habría"],hint:"Tú form of the subjunctive past perfect ends in -as.",s:"Si tú {1} venido, habrías disfrutado mucho.",a:"hubieras"},
        {type:"mc",q:"Which sentence uses the pluscuamperfecto de subjuntivo correctly?",opts:["Si hubiera sabido, te habría llamado","Si habría sabido, te hubiera llamado","Si he sabido, te llamaría","Si sé, te llamo"],ans:"Si hubiera sabido, te habría llamado",hint:"The si clause takes ___, the result clause takes ___."},
        {type:"mc",q:"The pluscuamperfecto de subjuntivo of 'escribir' for yo is:",opts:["hubiera escrito","habría escrito","hubiera escribido","he escrito"],ans:"hubiera escrito",hint:"Escribir has an irregular participle. The subjunctive form uses ___."}
  ]},
  {id:"esp26l3",title:"Si hubiera..., habría...",icon:"🔄",xp:20,board:true,steps:[
        {type:"intro",title:"Si hubiera..., habría...",desc:"Combine both tenses to express what would have happened if something else had happened. The classic past counterfactual structure.",goals:["Build complete past counterfactual sentences","Use si + pluscuamperfecto de subjuntivo + condicional compuesto","Express how things could have been different"]},
        {type:"teach",trg:"Si hubiera estudiado, habría aprobado.",src:"If I had studied, I would have passed.",pos:"intj",gender:null,phonetic:"see oo-BYEH-ra es-too-DYA-do, ah-BREE-ah ah-pro-BA-do",note:"The classic pattern:\nSi + hubiera + participle, habría + participle.\nBoth parts refer to something that did NOT happen.",example:"A: ¿Aprobaste el examen?\nB: No. Si hubiera estudiado más, habría aprobado.\nA: ¿No estudiaste nada?\nB: Muy poco. Si hubiera estudiado cada día, habría sacado buena nota.\nA: Pues a estudiar para el próximo.",exampleSrc:"A: Did you pass the exam?\nB: No. If I had studied more, I would have passed.\nA: You didn't study at all?\nB: Very little. If I had studied every day, I would have gotten a good grade.\nA: Well, time to study for the next one.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Si hubiera llovido, no habríamos ido a la playa.",src:"If it had rained, we wouldn't have gone to the beach.",pos:"intj",gender:null,phonetic:"see oo-BYEH-ra yo-VEE-do, no ah-BREE-ah-mos EE-do",note:"The si clause can use any subject.\nThe result clause shows what would have happened.",example:"A: ¡Qué bien lo pasamos en la playa!\nB: Tuvimos suerte con el tiempo.\nA: Si hubiera llovido, no habríamos ido.\nB: Habríamos ido al cine en su lugar.\nA: La playa fue mucho mejor.",exampleSrc:"A: We had such a great time at the beach!\nB: We were lucky with the weather.\nA: If it had rained, we wouldn't have gone.\nB: We would have gone to the movies instead.\nA: The beach was much better.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Si hubieras llegado antes, habrías conocido a mi hermana.",src:"If you had arrived earlier, you would have met my sister.",pos:"intj",gender:null,phonetic:"see oo-BYEH-ras ye-GA-do AN-tes, ah-BREE-as ko-no-SEE-do",note:"Notice how both clauses change subject freely.\nSi tú hubieras..., tú habrías... (same subject)\nSi tú hubieras..., ella habría... (different subjects)",example:"A: Llegué tarde a la fiesta.\nB: Si hubieras llegado antes, habrías conocido a mi hermana.\nA: ¡Qué pena! Quería conocerla.\nB: Si hubieras llegado a las siete, habríais cenado juntos.\nA: La próxima vez llegaré temprano.",exampleSrc:"A: I arrived late to the party.\nB: If you had arrived earlier, you would have met my sister.\nA: What a shame! I wanted to meet her.\nB: If you had arrived at seven, you would have had dinner together.\nA: Next time I'll arrive early.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Past counterfactual structure",text:"Formula: Si + hubiera/hubieras/etc. + participle, habría/habrías/etc. + participle\n\nBoth parts describe unreal past events:\n1. The condition (si clause): something that did NOT happen\n2. The result: what WOULD have happened\n\nThe order can be reversed:\nHabría aprobado si hubiera estudiado.",icon:"💡"},
        {type:"mc",q:"'Si hubiera tenido dinero, habría comprado el coche.' The speaker:",opts:["Bought the car","Did not buy the car","Will buy the car","Is buying the car"],ans:"Did not buy the car",hint:"Both actions are hypothetical and in the past. Neither actually happened."},
        {type:"mc",q:"Which correctly completes: 'Si hubiéramos salido antes, ___'?",opts:["habríamos llegado a tiempo","hubiéramos llegado a tiempo","hemos llegado a tiempo","llegaríamos a tiempo"],ans:"habríamos llegado a tiempo",hint:"The result clause of a past counterfactual uses the condicional compuesto."},
        {type:"fb",opts:["leído","leyendo","leer","leo"],hint:"Past participle of leer. Remember the accent on the -ido.",s:"Si hubiera {1} el correo, habría respondido.",a:"leído"},
        {type:"fb",opts:["participado","participando","participar","participas"],hint:"Regular -ar verb past participle: remove -ar, add -ado.",s:"Si hubieras {1}, habrías ganado el premio.",a:"participado"},
        {type:"mc",q:"In 'Habría ido si hubiera sabido', which clause comes first?",opts:["The result clause","The si clause","Both are si clauses","Neither has a clear order"],ans:"The result clause",hint:"The condicional compuesto (habría ido) is the ___, placed before si here."},
        {type:"teach",trg:"Si no hubiera perdido el tren, habría llegado a la reunión.",src:"If I hadn't missed the train, I would have arrived at the meeting.",pos:"intj",gender:null,phonetic:"see no oo-BYEH-ra per-DEE-do el tren",note:"Negative counterfactuals: Si NO hubiera + participle.\nExpresses: the bad thing happened, and it caused problems.",example:"A: ¿Por qué no fuiste a la reunión?\nB: Perdí el tren. Si no hubiera perdido el tren, habría llegado.\nA: ¿No había otro tren?\nB: Sí, pero habría llegado demasiado tarde.\nA: Mala suerte. Te envío las notas.",exampleSrc:"A: Why didn't you go to the meeting?\nB: I missed the train. If I hadn't missed the train, I would have arrived.\nA: Wasn't there another train?\nB: Yes, but I would have arrived too late.\nA: Bad luck. I'll send you the notes.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"drag_fill",hint:"The si clause needs the tú subjunctive form. The result uses yo conditional.",s:"Si {1} llamado, te {2} avisado.",blanks:{"1":"hubieras","2":"habría"},pool:["hubieras","habría","hubiera","habrías"]},
        {type:"mc",q:"Which sentence is a past counterfactual?",opts:["Si estudio, apruebo","Si estudiara, aprobaría","Si hubiera estudiado, habría aprobado","Si estudio, aprobaré"],ans:"Si hubiera estudiado, habría aprobado",hint:"Past counterfactuals use ___ + ___ with past participles."},
        {type:"match",pairs:[
          {trg:"Si hubiera sabido",src:"If I had known"},
          {trg:"habría venido",src:"I would have come"},
          {trg:"Si hubieras llamado",src:"If you had called"},
          {trg:"habríamos salido",src:"we would have left"},
          {trg:"Si no hubiera llovido",src:"If it hadn't rained"}
        ]},
        {type:"fb",opts:["estado","ser","estando","estoy"],hint:"Past participle of estar. The result expresses a state.",s:"Si ella hubiera aceptado, yo habría {1} muy contento.",a:"estado"},
        {type:"mc",q:"'Si hubieran invitado a Pedro, él habría traído su guitarra.' Who was NOT invited?",opts:["Pedro","The speaker","Both","We don't know"],ans:"Pedro",hint:"The si clause describes a past event that did not happen. Focus on who the si clause says was not invited."},
        {type:"drag_fill",hint:"Both parts use nosotros forms. One subjunctive, one conditional.",s:"Si {1} sabido la dirección, no nos {2} perdido.",blanks:{"1":"hubiéramos","2":"habríamos"},pool:["hubiéramos","habríamos","hubieran","habrían"]},
        {type:"mc",q:"'Si hubieran comprado los billetes antes, habrían pagado menos.' Who would have paid less?",opts:["They","We","You (singular)","I"],ans:"They",hint:"Hubieran and habrían are both third person plural forms."}
  ]},
  {id:"esp26l4",title:"Ojalá hubiera...",icon:"😔",xp:20,board:true,steps:[
        {type:"intro",title:"Ojalá hubiera...",desc:"Express deep regret about the past using ojalá with the pluscuamperfecto de subjuntivo. These are wishes about things that cannot be changed.",goals:["Use ojalá + hubiera + past participle for past regrets","Express wishes about unchangeable past events","Distinguish ojalá with present vs past subjunctive"]},
        {type:"teach",trg:"Ojalá hubiera estudiado más.",src:"I wish I had studied more.",pos:"intj",gender:null,phonetic:"oh-ha-LA oo-BYEH-ra es-too-DYA-do mas",note:"Ojalá + hubiera + participle = I wish I had...\nExpresses regret about something that cannot change.",example:"A: Suspendí el examen.\nB: ¿No estudiaste suficiente?\nA: No. Ojalá hubiera estudiado más.\nB: Todavía puedes repetirlo.\nA: Sí. Ojalá hubiera empezado antes, pero ahora estudiaré cada día.",exampleSrc:"A: I failed the exam.\nB: Didn't you study enough?\nA: No. I wish I had studied more.\nB: You can still retake it.\nA: Yes. I wish I had started earlier, but now I'll study every day.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Ojalá no hubiera dicho eso.",src:"I wish I hadn't said that.",pos:"intj",gender:null,phonetic:"oh-ha-LA no oo-BYEH-ra DEE-cho EH-so",note:"Ojalá no + hubiera = I wish I hadn't.\nDicho = irregular past participle of decir.",example:"A: Le dije algo horrible a mi amigo.\nB: ¿Qué le dijiste?\nA: Algo sobre su trabajo. Ojalá no hubiera dicho eso.\nB: ¿Has hablado con él después?\nA: No. Ojalá no hubiera dicho nada. Necesito disculparme.",exampleSrc:"A: I said something horrible to my friend.\nB: What did you say?\nA: Something about his job. I wish I hadn't said that.\nB: Have you talked to him since?\nA: No. I wish I hadn't said anything. I need to apologize.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Ojalá hubiera ido a la universidad.",src:"I wish I had gone to university.",pos:"intj",gender:null,phonetic:"oh-ha-LA oo-BYEH-ra EE-do",note:"Ido = past participle of ir (to go).\nOjalá hubiera ido = I wish I had gone.",example:"A: ¿Fuiste a la universidad?\nB: No. Ojalá hubiera ido.\nA: ¿Por qué no fuiste?\nB: No tenía dinero. Ojalá hubiera ido y hubiera estudiado medicina.\nA: Nunca es tarde. Hay programas para adultos.",exampleSrc:"A: Did you go to university?\nB: No. I wish I had gone.\nA: Why didn't you go?\nB: I didn't have money. I wish I had gone and studied medicine.\nA: It's never too late. There are programs for adults.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Ojalá: present wish vs past regret",text:"Ojalá + present subjunctive = wish for now or the future:\nOjalá llueva mañana. (I hope it rains tomorrow.)\n\nOjalá + imperfect subjunctive = unlikely present wish:\nOjalá tuviera más tiempo. (I wish I had more time.)\n\nOjalá + pluscuamperfecto de subjuntivo = past regret:\nOjalá hubiera tenido más tiempo. (I wish I had had more time.)\n\nOnly the last one is about the unchangeable past.",icon:"💡"},
        {type:"teach",trg:"Ojalá hubiéramos viajado juntos.",src:"I wish we had traveled together.",pos:"intj",gender:null,phonetic:"oh-ha-LA oo-BYEH-ra-mos vya-HA-do HOON-tos",note:"Hubiéramos = we had (subjunctive).\nOjalá works with any person, not just yo.",example:"A: ¿Recuerdas cuando tú fuiste a Japón?\nB: Sí. Ojalá hubiéramos viajado juntos.\nA: Yo estaba trabajando.\nB: Lo sé. Ojalá hubiéramos planeado mejor.\nA: Podemos ir juntos el próximo año.",exampleSrc:"A: Remember when you went to Japan?\nB: Yes. I wish we had traveled together.\nA: I was working.\nB: I know. I wish we had planned better.\nA: We can go together next year.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"mc",q:"'Ojalá hubiera dormido más' expresses:",opts:["A hope for tonight","A past regret","A future plan","A present state"],ans:"A past regret",hint:"Hubiera + participle places the wish firmly in the unchangeable ___."},
        {type:"mc",q:"Which sentence expresses a past regret?",opts:["Ojalá llueva mañana","Ojalá tuviera dinero","Ojalá hubiera comprado esa casa","Ojalá pueda venir"],ans:"Ojalá hubiera comprado esa casa",hint:"The pluscuamperfecto de subjuntivo (___ + participle) signals a past regret."},
        {type:"fb",opts:["hubiera","habría","hubieran","he"],hint:"After ojalá, the past regret uses the subjunctive form of haber.",s:"Ojalá no {1} perdido las llaves.",a:"hubiera"},
        {type:"fb",opts:["hubiera","habría","he","haya"],hint:"Ojalá + past regret requires the subjunctive past perfect.",s:"Ojalá {1} aceptado el trabajo.",a:"hubiera"},
        {type:"mc",q:"'Ojalá hubieras venido a la fiesta' is said to:",opts:["A group of people","One person informally","One person formally","Yourself"],ans:"One person informally",hint:"Hubieras is the tú form of the pluscuamperfecto de subjuntivo."},
        {type:"teach",trg:"Ojalá hubiera sabido antes.",src:"I wish I had known earlier.",pos:"intj",gender:null,phonetic:"oh-ha-LA oo-BYEH-ra sa-BEE-do AN-tes",note:"Sabido = past participle of saber.\nOjalá hubiera sabido = I wish I had known.",example:"A: ¿Sabías que la entrada era gratis el domingo?\nB: No. Ojalá hubiera sabido antes.\nA: Lo publicaron en su página web.\nB: No la vi. Ojalá hubiera sabido, habríamos ido todos.\nA: El próximo mes vuelve a ser gratis.",exampleSrc:"A: Did you know admission was free on Sunday?\nB: No. I wish I had known earlier.\nA: They posted it on their website.\nB: I didn't see it. I wish I had known, we all would have gone.\nA: Next month it's free again.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"drag_fill",hint:"Past regret with ojalá: subjunctive haber + irregular participle of decir.",s:"Ojalá {1} {2} la verdad desde el principio.",blanks:{"1":"hubiera","2":"dicho"},pool:["hubiera","habría","dicho","decido"]},
        {type:"mc",q:"Which is NOT a correct use of ojalá for past regret?",opts:["Ojalá hubiera ido","Ojalá no hubiera dicho eso","Ojalá habría comprado la casa","Ojalá hubiéramos llegado antes"],ans:"Ojalá habría comprado la casa",hint:"After ___á, always use subjunctive forms (hubiera), never conditional (___)."},
        {type:"match",pairs:[
          {trg:"Ojalá hubiera sabido",src:"I wish I had known"},
          {trg:"Ojalá hubieras venido",src:"I wish you had come"},
          {trg:"Ojalá no hubiera llovido",src:"I wish it hadn't rained"},
          {trg:"Ojalá hubiéramos ganado",src:"I wish we had won"},
          {trg:"Ojalá hubieran avisado",src:"I wish they had warned us"}
        ]},
        {type:"mc",q:"You regret not calling your mother yesterday. You say:",opts:["Ojalá llame a mi madre","Ojalá llamara a mi madre","Ojalá hubiera llamado a mi madre","Ojalá he llamado a mi madre"],ans:"Ojalá hubiera llamado a mi madre",hint:"Yesterday is past and unchangeable. Use ___ + past participle."},
        {type:"fb",opts:["hubiéramos","habríamos","hubieran","hemos"],hint:"Nosotros form of the subjunctive past perfect after ojalá.",s:"Ojalá no nos {1} mudado de esa ciudad.",a:"hubiéramos"},
        {type:"mc",q:"'Ojalá hubiera aprendido a tocar la guitarra de joven.' The speaker:",opts:["Learned guitar as a child","Did not learn guitar as a child","Is currently learning guitar","Plans to learn guitar"],ans:"Did not learn guitar as a child",hint:"Ojalá + hubiera expresses regret about something that ___ NOT happen."}
  ]},
  {id:"esp26l5",title:"Podrías haber...",icon:"😤",xp:20,board:true,steps:[
        {type:"intro",title:"Podrías haber...",desc:"Express reproaches and criticism about past actions using the conditional of modal verbs + haber + past participle.",goals:["Use podrías haber + participle for reproaches","Use deberías haber + participle for obligations not met","Criticize past inaction politely and directly"]},
        {type:"teach",trg:"Podrías haber llamado.",src:"You could have called.",pos:"intj",gender:null,phonetic:"po-DREE-as ah-BER ya-MA-do",note:"Podrías haber + participle = You could have...\nA soft reproach: you had the ability but didn't act.",example:"A: Llegué muy tarde a casa.\nB: Podrías haber llamado para avisar.\nA: Se me olvidó.\nB: Estuve preocupada. Podrías haber mandado un mensaje al menos.\nA: Tienes razón. Lo siento mucho.",exampleSrc:"A: I got home very late.\nB: You could have called to let me know.\nA: I forgot.\nB: I was worried. You could have sent a message at least.\nA: You're right. I'm very sorry.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Deberías haber venido.",src:"You should have come.",pos:"intj",gender:null,phonetic:"deh-beh-REE-as ah-BER ve-NEE-do",note:"Deberías haber + participle = You should have...\nStronger than podrías: implies obligation, not just ability.",example:"A: No fui a la reunión del equipo.\nB: Deberías haber venido. Era importante.\nA: No me sentía bien.\nB: Deberías haber avisado al jefe al menos.\nA: Sí, tienes razón. Hablaré con él mañana.",exampleSrc:"A: I didn't go to the team meeting.\nB: You should have come. It was important.\nA: I wasn't feeling well.\nB: You should have told the boss at least.\nA: Yes, you're right. I'll talk to him tomorrow.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Podría haber sido peor.",src:"It could have been worse.",pos:"intj",gender:null,phonetic:"po-DREE-ah ah-BER SEE-do peh-OR",note:"Podría haber sido = It could have been.\nUsed to put things in perspective, not as a reproach.",example:"A: Me caí en la calle y me rompí el brazo.\nB: ¡Qué mal! Pero podría haber sido peor.\nA: Lo sé. Podría haber sido la pierna.\nB: Exacto. Podría haber sido mucho más grave.\nA: Tienes razón. Al menos solo es el brazo.",exampleSrc:"A: I fell in the street and broke my arm.\nB: How awful! But it could have been worse.\nA: I know. It could have been the leg.\nB: Exactly. It could have been much more serious.\nA: You're right. At least it's just the arm.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"No deberías haber dicho eso.",src:"You shouldn't have said that.",pos:"intj",gender:null,phonetic:"no deh-beh-REE-as ah-BER DEE-cho EH-so",note:"No deberías haber = You shouldn't have.\nThe strongest form of reproach with deber.",example:"A: Le dije a María que su vestido era feo.\nB: No deberías haber dicho eso. La heriste.\nA: No era mi intención.\nB: No deberías haber sido tan directo.\nA: Voy a disculparme con ella.",exampleSrc:"A: I told María her dress was ugly.\nB: You shouldn't have said that. You hurt her.\nA: That wasn't my intention.\nB: You shouldn't have been so direct.\nA: I'm going to apologize to her.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Reproach strength scale",text:"From softest to strongest:\n\n1. Podrías haber llamado. (You could have called.)\n   Implies ability. Soft suggestion.\n\n2. Deberías haber llamado. (You should have called.)\n   Implies obligation. Clear reproach.\n\n3. Tendrías que haber llamado. (You would have had to call.)\n   Implies necessity. Firm reproach.\n\nAll follow: conditional of modal + haber + participle.",icon:"💡"},
        {type:"teach",trg:"Tendría que haber preguntado.",src:"I should have asked.",pos:"intj",gender:null,phonetic:"ten-DREE-ah keh ah-BER pre-goon-TA-do",note:"Tendría que haber = I should have (stronger).\nTendrías que haber = You should have (stronger reproach).",example:"A: Compré el regalo equivocado.\nB: Tendría que haber preguntado qué quería.\nA: Pensé que lo sabía.\nB: Tendrías que haber preguntado a su hermana.\nA: Sí. Tendría que haber sido más cuidadoso.",exampleSrc:"A: I bought the wrong gift.\nB: I should have asked what she wanted.\nA: I thought I knew.\nB: You should have asked her sister.\nA: Yes. I should have been more careful.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"mc",q:"'Podrías haber avisado' is:",opts:["A strong command","A soft reproach","A question","A past tense statement"],ans:"A soft reproach",hint:"Podrías implies you had the ability but chose not to act."},
        {type:"mc",q:"Which expresses the STRONGEST reproach?",opts:["Podrías haber llamado","Deberías haber llamado","Tendrías que haber llamado","Habrías llamado"],ans:"Tendrías que haber llamado",hint:"Tener ___ implies necessity, making it the firmest reproach."},
        {type:"fb",opts:["Deberías","Podrás","Debías","Puedes"],hint:"This modal conditional form expresses past obligation not met.",s:"{1} haber llegado a tiempo.",a:"Deberías"},
        {type:"fb",opts:["hecho","hacido","hacer","haciendo"],hint:"Irregular past participle of hacer.",s:"No deberías haber {1} eso.",a:"hecho"},
        {type:"mc",q:"A friend forgot your birthday. You say:",opts:["Podrías haber recordado","Podrás recordar","Puedes haber recordado","Podías recordar"],ans:"Podrías haber recordado",hint:"Conditional of poder + ___ + participle for a past reproach."},
        {type:"drag_fill",hint:"Tener que = have to. The participle of pensar is regular.",s:"{1} que haber {2} antes de actuar.",blanks:{"1":"Tendrías","2":"pensado"},pool:["Tendrías","Habrías","pensado","pensando"]},
        {type:"mc",q:"'Podría haber sido peor' expresses:",opts:["A reproach","Perspective or consolation","A command","An apology"],ans:"Perspective or consolation",hint:"This phrase puts a bad situation in context by noting it could have been worse."},
        {type:"match",pairs:[
          {trg:"Podrías haber llamado",src:"You could have called"},
          {trg:"Deberías haber venido",src:"You should have come"},
          {trg:"Tendría que haber preguntado",src:"I should have asked"},
          {trg:"No deberías haber dicho eso",src:"You shouldn't have said that"},
          {trg:"Podría haber sido peor",src:"It could have been worse"}
        ]},
        {type:"fb",opts:["puesto","ponido","poniendo","poner"],hint:"Irregular past participle of poner.",s:"Podrías haber {1} un poco más de esfuerzo.",a:"puesto"},
        {type:"mc",q:"Your coworker didn't finish the report. You say firmly:",opts:["Podrías haber terminado el informe","Tendrías que haber terminado el informe","Habrás terminado el informe","Terminarías el informe"],ans:"Tendrías que haber terminado el informe",hint:"The firmest reproach uses ___ ___ ___ for unmet obligation."},
        {type:"fb",opts:["deberías","podrás","debías","puedes"],hint:"A reproach about going out without an umbrella. Conditional of deber.",s:"No {1} haber salido sin paraguas.",a:"deberías"}
  ]},
  {id:"esp26l6",title:"¿Qué habría pasado si...?",icon:"🌍",xp:20,board:true,steps:[
        {type:"intro",title:"¿Qué habría pasado si...?",desc:"Use past counterfactuals to imagine alternative histories and explore how different decisions would have changed outcomes.",goals:["Ask 'what would have happened if' questions","Build extended alternative past narratives","Combine counterfactuals with reproaches and regrets"]},
        {type:"teach",trg:"¿Qué habría pasado si...?",src:"What would have happened if...?",pos:"intj",gender:null,phonetic:"keh ah-BREE-ah pa-SA-do see",note:"The classic alternative history opener.\nQué habría pasado + si + hubiera = what if things had been different?",example:"A: ¿Qué habría pasado si no hubieras aceptado ese trabajo?\nB: No lo sé. Habría seguido buscando.\nA: ¿Y si hubieras aceptado el otro?\nB: Habría ganado menos, pero habría vivido en Barcelona.\nA: A veces pienso en las decisiones que no tomamos.",exampleSrc:"A: What would have happened if you hadn't accepted that job?\nB: I don't know. I would have kept looking.\nA: And if you had accepted the other one?\nB: I would have earned less, but I would have lived in Barcelona.\nA: Sometimes I think about the decisions we didn't make.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Todo habría sido diferente.",src:"Everything would have been different.",pos:"intj",gender:null,phonetic:"TO-do ah-BREE-ah SEE-do dee-fe-REN-te",note:"A powerful closing statement for alternative narratives.\nHabría sido = would have been.",example:"A: Si no me hubiera mudado a Madrid, nunca habría conocido a mi esposa.\nB: Todo habría sido diferente.\nA: Completamente diferente. No tendríamos a nuestros hijos.\nB: Es curioso cómo una decisión lo cambia todo.\nA: Todo habría sido diferente si hubiera tomado otro camino.",exampleSrc:"A: If I hadn't moved to Madrid, I never would have met my wife.\nB: Everything would have been different.\nA: Completely different. We wouldn't have our children.\nB: It's funny how one decision changes everything.\nA: Everything would have been different if I had taken another path.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Si no hubiera existido el internet, la vida habría sido muy distinta.",src:"If the internet hadn't existed, life would have been very different.",pos:"intj",gender:null,phonetic:"see no oo-BYEH-ra eg-sees-TEE-do el in-ter-NET",note:"Extended alternative narratives use multiple condicional compuesto clauses.\nEach habría + participle adds another consequence.",example:"A: ¿Cómo crees que sería la vida sin internet?\nB: Si no hubiera existido, la vida habría sido muy distinta.\nA: No habríamos podido trabajar desde casa.\nB: Ni habríamos conocido a tanta gente.\nA: Habríamos ido a la biblioteca para todo.",exampleSrc:"A: How do you think life would be without the internet?\nB: If it hadn't existed, life would have been very different.\nA: We wouldn't have been able to work from home.\nB: Nor would we have met so many people.\nA: We would have gone to the library for everything.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"tip",title:"Building alternative narratives",text:"Start with a si clause, then chain consequences:\n\nSi X hubiera pasado...\n  habría ocurrido A,\n  no habríamos hecho B,\n  y todo habría sido C.\n\nYou can also ask others:\n  ¿Qué habrías hecho tú?\n  ¿Cómo habría reaccionado él?\n  ¿Dónde habríamos vivido?",icon:"💡"},
        {type:"mc",q:"'¿Qué habría pasado si no hubiera llovido?' asks about:",opts:["A future plan","An alternative past scenario","A present situation","A real event"],ans:"An alternative past scenario",hint:"Hubiera + habría together create a hypothetical ___ world."},
        {type:"mc",q:"Which continues 'Si no hubiera nacido en España...'?",opts:["habría hablado otro idioma","hablo otro idioma","hablaré otro idioma","hablaba otro idioma"],ans:"habría hablado otro idioma",hint:"The result of a past counterfactual requires the condicional compuesto."},
        {type:"fb",opts:["habrías","hubieras","habías","has"],hint:"Asking someone what they would have done. Tú conditional form.",s:"¿Qué {1} hecho tú en mi lugar?",a:"habrías"},
        {type:"teach",trg:"Nunca habría imaginado este resultado.",src:"I never would have imagined this outcome.",pos:"intj",gender:null,phonetic:"NOON-ka ah-BREE-ah ee-ma-hee-NA-do",note:"Nunca habría + participle = I never would have...\nExpresses surprise at how things turned out.",example:"A: Hace diez años vivía en un pueblo pequeño.\nB: ¿Y ahora diriges una empresa?\nA: Nunca habría imaginado este resultado.\nB: Si no hubieras tomado esa decisión, nada de esto existiría.\nA: Es verdad. Nunca habría imaginado dónde estaría hoy.",exampleSrc:"A: Ten years ago I lived in a small town.\nB: And now you run a company?\nA: I never would have imagined this outcome.\nB: If you hadn't made that decision, none of this would exist.\nA: That's true. I never would have imagined where I'd be today.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"fb",opts:["sido","estar","siendo","soy"],hint:"Past participle of ser. The si clause expresses an unreal past condition.",s:"Si hubiera {1} más joven, habría viajado por todo el mundo.",a:"sido"},
        {type:"drag_fill",hint:"First person: si clause uses subjunctive hubiera, result uses conditional habría.",s:"Si no {1} conocido a Pedro, nunca {2} empezado este negocio.",blanks:{"1":"hubiera","2":"habría"},pool:["hubiera","habría","hubieras","habrías"]},
        {type:"mc",q:"'Habríamos viajado por toda Europa' means:",opts:["We will travel across Europe","We traveled across Europe","We would have traveled across Europe","We are traveling across Europe"],ans:"We would have traveled across Europe",hint:"Habríamos + participle is the nosotros condicional compuesto."},
        {type:"mc",q:"Which question asks someone to imagine an alternative past?",opts:["¿Qué haces aquí?","¿Qué habrías hecho tú?","¿Qué harás mañana?","¿Qué hiciste ayer?"],ans:"¿Qué habrías hecho tú?",hint:"The condicional compuesto invites someone to speculate about what they would have done."},
        {type:"match",pairs:[
          {trg:"¿Qué habría pasado?",src:"What would have happened?"},
          {trg:"Todo habría sido diferente",src:"Everything would have been different"},
          {trg:"Nunca habría imaginado",src:"I never would have imagined"},
          {trg:"No habríamos podido",src:"We wouldn't have been able to"},
          {trg:"Habrían cambiado las cosas",src:"Things would have changed"}
        ]},
        {type:"fb",opts:["hubieran","hubiera","habría","habrían"],hint:"Los aviones is plural. The subjunctive form needs the plural ending.",s:"Si no {1} existido los aviones, el mundo habría sido más pequeño.",a:"hubieran"},
        {type:"mc",q:"In a chain of consequences, each new result uses:",opts:["Hubiera + participle","Habría + participle","The present tense","The preterite"],ans:"Habría + participle",hint:"Every additional consequence in the result chain uses the condicional compuesto."},
        {type:"drag_fill",hint:"Asking tú about an alternative past. Conditional of haber + irregular participle of hacer.",s:"¿Qué {1} {2} si hubieras nacido en otro país?",blanks:{"1":"habrías","2":"hecho"},pool:["habrías","hubieras","hecho","hacido"]},
        {type:"mc",q:"'Si no hubiera existido la electricidad, no habríamos tenido internet.' This sentence has:",opts:["One counterfactual clause","Two counterfactual clauses","Three counterfactual clauses","No counterfactual clauses"],ans:"Two counterfactual clauses",hint:"Count the compound verb forms: hubiera existido (condition) and habríamos tenido (result)."}
  ]},
  {id:"esp26l7",title:"Tres condicionales",icon:"📊",xp:20,board:true,steps:[
        {type:"intro",title:"Tres condicionales",desc:"Compare and contrast all three types of Spanish conditionals: real, unlikely present, and impossible past.",goals:["Distinguish Type 1 (real), Type 2 (unlikely), and Type 3 (impossible past)","Choose the correct conditional type for each situation","Build sentences with all three types"]},
        {type:"tip",title:"Three conditional types in Spanish",text:"Type 1 (Real/Possible): Si + presente, futuro/presente\n  Si llueve, no iremos. (If it rains, we won't go.)\n\nType 2 (Unlikely/Hypothetical present): Si + imperfecto de subjuntivo, condicional\n  Si lloviera, no iríamos. (If it rained, we wouldn't go.)\n\nType 3 (Impossible past): Si + pluscuamperfecto de subjuntivo, condicional compuesto\n  Si hubiera llovido, no habríamos ido. (If it had rained, we wouldn't have gone.)\n\nType 1 = maybe it will happen.\nType 2 = probably won't happen.\nType 3 = definitely didn't happen.",icon:"💡"},
        {type:"teach",trg:"Si tengo tiempo, iré al gimnasio.",src:"If I have time, I will go to the gym.",pos:"intj",gender:null,phonetic:"see TEN-go TYEM-po, ee-REH al heem-NA-syo",note:"Type 1: Si + presente + futuro.\nReal possibility. It might actually happen today.",example:"A: ¿Vas al gimnasio hoy?\nB: Si tengo tiempo, iré al gimnasio.\nA: Terminas a las cinco, ¿no?\nB: Sí. Si termino a tiempo, iré directo.\nA: Te espero allí a las seis.",exampleSrc:"A: Are you going to the gym today?\nB: If I have time, I will go to the gym.\nA: You finish at five, right?\nB: Yes. If I finish on time, I'll go straight there.\nA: I'll wait for you there at six.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Si tuviera tiempo, iría al gimnasio.",src:"If I had time, I would go to the gym.",pos:"intj",gender:null,phonetic:"see too-VYEH-ra TYEM-po, ee-REE-ah",note:"Type 2: Si + imperfecto de subjuntivo + condicional.\nUnlikely but not impossible. The speaker doubts it will happen.",example:"A: ¿Por qué no vas al gimnasio?\nB: Si tuviera tiempo, iría. Pero estoy demasiado ocupado.\nA: ¿Y si cambiaras tu horario?\nB: Si tuviera un horario flexible, iría tres veces a la semana.\nA: Deberías hablar con tu jefe.",exampleSrc:"A: Why don't you go to the gym?\nB: If I had time, I would go. But I'm too busy.\nA: What if you changed your schedule?\nB: If I had a flexible schedule, I would go three times a week.\nA: You should talk to your boss.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"teach",trg:"Si hubiera tenido tiempo, habría ido al gimnasio.",src:"If I had had time, I would have gone to the gym.",pos:"intj",gender:null,phonetic:"see oo-BYEH-ra te-NEE-do TYEM-po, ah-BREE-ah EE-do",note:"Type 3: Si + pluscuamperfecto de subjuntivo + condicional compuesto.\nImpossible. Yesterday is over. The time is gone.",example:"A: ¿Fuiste al gimnasio ayer?\nB: No. Si hubiera tenido tiempo, habría ido.\nA: Estuviste muy ocupado.\nB: Sí. Si hubiera tenido una hora libre, habría ido sin duda.\nA: Hoy hay que intentarlo.",exampleSrc:"A: Did you go to the gym yesterday?\nB: No. If I had had time, I would have gone.\nA: You were very busy.\nB: Yes. If I had had a free hour, I would have gone for sure.\nA: Today we have to try.",funFact:"Spanish is the fourth most spoken language worldwide, with 500+ million native speakers."},
        {type:"mc",q:"'Si llueve, no saldremos.' is which conditional type?",opts:["Type 1: real/possible","Type 2: unlikely","Type 3: impossible past","None of these"],ans:"Type 1: real/possible",hint:"Present tense in the si clause + future in the result = a ___ possibility."},
        {type:"mc",q:"'Si tuviera dinero, compraría un coche.' is which type?",opts:["Type 1: real/possible","Type 2: unlikely present","Type 3: impossible past","Mixed type"],ans:"Type 2: unlikely present",hint:"Imperfect subjunctive + conditional = hypothetical but ___ or future."},
        {type:"mc",q:"'Si hubiera tenido dinero, habría comprado un coche.' is which type?",opts:["Type 1: real/possible","Type 2: unlikely present","Type 3: impossible past","A reproach"],ans:"Type 3: impossible past",hint:"Pluscuamperfecto de subjuntivo + condicional compuesto = the ___ cannot be changed."},
        {type:"fb",opts:["estudias","estudiaras","hubieras estudiado","estudies"],hint:"Type 1 uses the present tense in the si clause.",s:"Si {1} más, aprobarás.",a:"estudias"},
        {type:"fb",opts:["estudiaras","estudias","hubieras estudiado","estudies"],hint:"Type 2 uses the imperfect subjunctive in the si clause.",s:"Si {1} más, aprobarías.",a:"estudiaras"},
        {type:"fb",opts:["habrías aprobado","aprobarás","aprobarías","apruebas"],hint:"Type 3 result clause uses the condicional compuesto.",s:"Si hubieras estudiado más, {1}.",a:"habrías aprobado"},
        {type:"mc",q:"You missed the bus yesterday. Which type expresses regret?",opts:["Si pierdo el bus, llego tarde","Si perdiera el bus, llegaría tarde","Si hubiera perdido el bus, habría llegado tarde","Si pierda el bus, llegaré tarde"],ans:"Si hubiera perdido el bus, habría llegado tarde",hint:"The event is in the past and cannot change. Only Type 3 fits."},
        {type:"drag_fill",hint:"This is a Type 2 hypothetical about the present. Imperfect subjunctive + conditional.",s:"Si {1} rico, {2} una isla.",blanks:{"1":"fuera","2":"compraría"},pool:["fuera","hubiera sido","compraría","habría comprado"]},
        {type:"match",pairs:[
          {trg:"Si tengo, compro",src:"Type 1: If I have, I buy"},
          {trg:"Si tuviera, compraría",src:"Type 2: If I had, I would buy"},
          {trg:"Si hubiera tenido, habría comprado",src:"Type 3: If I had had, I would have bought"}
        ]},
        {type:"mc",q:"A friend asks: 'What would you do if you won the lottery?' Which type?",opts:["Type 1","Type 2","Type 3","Not a conditional"],ans:"Type 2",hint:"Winning the lottery is unlikely but possible in the future. This is hypothetical present."},
        {type:"mc",q:"Which is correct for: 'If I had known, I would have told you'?",opts:["Si sé, te digo","Si supiera, te diría","Si hubiera sabido, te habría dicho","Si sabía, te decía"],ans:"Si hubiera sabido, te habría dicho",hint:"Past event that did not happen requires Type 3."},
        {type:"drag_fill",hint:"Type 3: si clause = third person subjunctive, result = nosotros conditional.",s:"Si {1} llovido, no {2} ido a la playa.",blanks:{"1":"hubiera","2":"habríamos"},pool:["hubiera","habría","habríamos","hubiéramos"]},
        {type:"mc",q:"To say 'If I were rich, I would travel': which conditional type?",opts:["Type 1: Si soy rico, viajo","Type 2: Si fuera rico, viajaría","Type 3: Si hubiera sido rico, habría viajado","None of these"],ans:"Type 2: Si fuera rico, viajaría",hint:"An unlikely present hypothesis uses the imperfect subjunctive + conditional."}
  ]},
  {id:"esp26l8",title:"Repaso: condicional compuesto",icon:"🎯",xp:20,board:true,steps:[
        {type:"intro",title:"Repaso: condicional compuesto",desc:"Practice everything from this unit: condicional compuesto, pluscuamperfecto de subjuntivo, past counterfactuals, regrets, reproaches, and all three conditional types.",goals:["Accurately form past counterfactual sentences","Choose between ojalá, reproaches, and neutral counterfactuals","Switch between all three conditional types"]},
        {type:"mc",q:"'Habríamos ido a la playa si hubiera hecho sol.' The weather was:",opts:["Sunny","Not sunny","Rainy but they went anyway","Unknown"],ans:"Not sunny",hint:"Both parts are counterfactual. The condition (sun) was not met."},
        {type:"fb",opts:["hubiera","habría","he","haya"],hint:"The si clause in a past counterfactual uses the subjunctive form.",s:"Si {1} sabido, te habría llamado.",a:"hubiera"},
        {type:"mc",q:"Which expresses a past regret with ojalá?",opts:["Ojalá llueva mañana","Ojalá tuviera más dinero","Ojalá hubiera comprado esa casa","Ojalá puedo ir"],ans:"Ojalá hubiera comprado esa casa",hint:"Past regret requires ___á + pluscuamperfecto de subjuntivo."},
        {type:"drag_fill",hint:"Addressing tú: si clause = subjunctive, result = conditional.",s:"Si {1} estudiado, no {2} suspendido.",blanks:{"1":"hubieras","2":"habrías"},pool:["hubieras","habrías","hubiera","habría"]},
        {type:"mc",q:"Your colleague forgot the meeting. A firm reproach is:",opts:["Podrías haber venido","Deberías haber venido","Tendrías que haber venido","Habrías venido"],ans:"Tendrías que haber venido",hint:"Tener ___ implies the strongest level of obligation."},
        {type:"fb",opts:["hubiera","habría","he","haya"],hint:"After ojalá, past regret always uses the subjunctive form of haber.",s:"Ojalá no {1} dicho eso en la reunión.",a:"hubiera"},
        {type:"mc",q:"'Si tengo hambre, como algo' is:",opts:["Type 3: impossible past","Type 2: unlikely present","Type 1: real/possible","A reproach"],ans:"Type 1: real/possible",hint:"Present tense in both clauses = a ___, everyday possibility."},
        {type:"fb",opts:["Deberías","Podrás","Debías","Puedes"],hint:"A reproach about a past obligation not met. Conditional of deber.",s:"{1} haber preguntado antes de decidir.",a:"Deberías"},
        {type:"mc",q:"'¿Qué habrías hecho tú?' translates as:",opts:["What did you do?","What would you have done?","What will you do?","What are you doing?"],ans:"What would you have done?",hint:"Habrías + participle is the condicional compuesto in question form."},
        {type:"drag_fill",hint:"Si clause: third person singular (the rain). Result: nosotros conditional.",s:"Si no {1} llovido, {2} ido al parque.",blanks:{"1":"hubiera","2":"habríamos"},pool:["hubiera","habríamos","habrían","hubiéramos"]},
        {type:"match",pairs:[
          {trg:"Si estudio, apruebo",src:"Type 1: real"},
          {trg:"Si estudiara, aprobaría",src:"Type 2: unlikely"},
          {trg:"Si hubiera estudiado, habría aprobado",src:"Type 3: impossible past"},
          {trg:"Ojalá hubiera estudiado",src:"Past regret"},
          {trg:"Deberías haber estudiado",src:"Reproach"}
        ]},
        {type:"mc",q:"Which is grammatically WRONG?",opts:["Si hubiera sabido, habría venido","Si habría sabido, hubiera venido","Ojalá hubiera sabido","Podrías haber avisado"],ans:"Si habría sabido, hubiera venido",hint:"The si clause NEVER takes ___. It must use the subjunctive ___."},
        {type:"fb",opts:["habría","hubiera","he","había"],hint:"Independent clause: I never would have imagined. Uses the conditional.",s:"Nunca {1} imaginado que viviría en otro país.",a:"habría"},
        {type:"mc",q:"Expressing consolation after a setback:",opts:["Tendrías que haber hecho más","Ojalá hubiera sido diferente","Podría haber sido peor","No deberías haber venido"],ans:"Podría haber sido peor",hint:"This phrase puts things in perspective. It could have been worse."},
        {type:"drag_fill",hint:"Ojalá + subjunctive haber + past participle of aprovechar.",s:"Ojalá {1} {2} esa oportunidad cuando la tuve.",blanks:{"1":"hubiera","2":"aprovechado"},pool:["hubiera","habría","aprovechado","aprovechando"]},
        {type:"fb",opts:["hubiera","habría","hubieras","habrían"],hint:"Ella is third person singular. Si clause takes the subjunctive.",s:"Si ella no {1} venido, la fiesta habría sido aburrida.",a:"hubiera"},
        {type:"mc",q:"You did NOT study and you failed. To express regret:",opts:["Ojalá estudie más","Si estudio, apruebo","Ojalá hubiera estudiado más","Si estudiara, aprobaría"],ans:"Ojalá hubiera estudiado más",hint:"The exam is past. Regret about an unchangeable past uses ___á + ___."},
        {type:"mc",q:"'Todo habría sido diferente si hubiéramos tomado otra decisión.' How many counterfactual verbs?",opts:["One","Two","Three","Four"],ans:"Two",hint:"Count the compound verb forms: habría sido and hubiéramos tomado."}
  ]}
]};
